import { useState, useEffect } from 'react';

const BASE = "https://raw.githubusercontent.com/jkappelmeier/jkappelmeier.github.io/main/Data";

const DEM = '#2166ac';
const REP = '#d6232a';

function parseCSVMulti(text) {
  const lines = text.trim().split("\n");
  const headers = lines[0].split(",").map(h => h.trim());
  return lines.slice(1).map(line => {
    const vals = line.split(",").map(v => v.trim());
    const obj = {};
    headers.forEach((h, i) => obj[h] = vals[i]);
    return obj;
  });
}

function pct(v, d=1) { return (parseFloat(v)*100).toFixed(d) + "%"; }

function FlipBadge({ isDem }) {
  return (
    <span style={{
      background: isDem ? '#dbeafe' : '#fee2e2',
      color: isDem ? '#1e40af' : '#991b1b',
      fontSize: '11px',
      fontWeight: 500,
      padding: '2px 7px',
      borderRadius: '99px',
      whiteSpace: 'nowrap',
    }}>+ Flip</span>
  );
}

function SortableTable({ columns, data, defaultSort, defaultDir = 'asc', pageSize = 10, colWidths = [] }) {
  const [sortCol, setSortCol] = useState(defaultSort);
  const [sortDir, setSortDir] = useState(defaultDir);
  const [shown, setShown] = useState(pageSize);

  const handleSort = (col) => {
    if (sortCol === col) {
      setSortDir(d => d === 'asc' ? 'desc' : 'asc');
    } else {
      setSortCol(col);
      setSortDir('asc');
    }
    setShown(pageSize);
  };

  const sorted = [...data].sort((a, b) => {
    const col = columns.find(c => c.key === sortCol);
    const va = col?.sortVal ? col.sortVal(a) : a[sortCol];
    const vb = col?.sortVal ? col.sortVal(b) : b[sortCol];
    if (va < vb) return sortDir === 'asc' ? -1 : 1;
    if (va > vb) return sortDir === 'asc' ? 1 : -1;
    return 0;
  });

  const arrow = (col) => {
    if (sortCol !== col) return ' ↕';
    return sortDir === 'asc' ? ' ↑' : ' ↓';
  };

  return (
    <>
      <table className="race-table">
        {colWidths.length > 0 && (
          <colgroup>
            {colWidths.map((w, i) => <col key={i} style={{ width: w }} />)}
          </colgroup>
        )}
        <thead>
          <tr>
            {columns.map(col => (
              <th key={col.key} onClick={() => handleSort(col.key)} style={{ cursor: 'pointer', userSelect: 'none', whiteSpace: 'nowrap' }}>
                {col.label}{arrow(col.key)}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {sorted.slice(0, shown).map((row, i) => (
            <tr key={i} className={row._rowClass || ''}>
              {columns.map(col => (
                <td key={col.key} className={col.className?.(row) || ''}>
                  {col.render ? col.render(row) : row[col.key]}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
      <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', margin: '0.75rem 0 1.5rem', fontSize: '13px', color: '#666' }}>
        <span>{Math.min(shown, sorted.length)} of {sorted.length}</span>
        {shown < sorted.length && (
          <button onClick={() => setShown(s => s + pageSize)} style={{ padding: '4px 12px', borderRadius: 6, border: '1px solid #ccc', background: '#fff', cursor: 'pointer', fontSize: '13px' }}>
            Show more
          </button>
        )}
        {shown > pageSize && (
          <button onClick={() => setShown(pageSize)} style={{ padding: '4px 12px', borderRadius: 6, border: '1px solid #ccc', background: '#fff', cursor: 'pointer', fontSize: '13px' }}>
            Show less
          </button>
        )}
      </div>
    </>
  );
}

const GEO_URL = "https://datawrapper.dwcdn.net/gOluU/4/";
const HEX_URL = "https://datawrapper.dwcdn.net/GvPGa/1/";

export default function Gov() {
  const [races, setRaces] = useState([]);
  const [loading, setLoading] = useState(true);
  const [mapType, setMapType] = useState('geographic');

  useEffect(() => {
    fetch(`${BASE}/GovSnapshot.csv`)
      .then(r => r.text())
      .then(text => {
        setRaces(parseCSVMulti(text));
        setLoading(false);
      });
  }, []);

  if (loading) return <p>Loading...</p>;

  const raceData = races.map(r => {
    const demEst = parseFloat(r.DemEstimate);
    const margin = (demEst - 0.5) * 200;
    const closeness = Math.abs(demEst - 0.5);
    const isDemFlip = r.Flip === '1' && parseFloat(r.DemChance) > 0.5;
    return { ...r, _margin: margin, _closeness: closeness, _isDemFlip: isDemFlip, _rowClass: r.Flip === '1' ? 'flip-row' : '' };
  });

  const raceColumns = [
    { key: 'GeographyName', label: 'State', sortVal: r => r.GeographyName },
    { key: 'ElectionName', label: 'Race', sortVal: r => r.ElectionName },
    { key: 'DemCandidate', label: 'Dem', sortVal: r => r.DemCandidate },
    { key: 'RepCandidate', label: 'Rep', sortVal: r => r.RepCandidate },
    { key: 'DemChance', label: 'Dem chance', sortVal: r => parseFloat(r.DemChance), className: () => 'dem', render: r => pct(r.DemChance) },
    { key: 'RepChance', label: 'Rep chance', sortVal: r => parseFloat(r.RepChance), className: () => 'rep', render: r => pct(r.RepChance) },
    { key: '_margin', label: 'Margin', sortVal: r => r._margin, className: r => r._margin >= 0 ? 'dem' : 'rep', render: r => `${r._margin >= 0 ? 'D+' : 'R+'}${Math.abs(r._margin).toFixed(1)}%` },
    { key: '_closeness', label: 'Competitiveness', sortVal: r => r._closeness, className: () => '', render: r => `${Math.abs(r._margin).toFixed(1)}% margin` },
    { key: 'Flip', label: 'Flip', sortVal: r => r.Flip, render: r => r.Flip === '1' ? <FlipBadge isDem={r._isDemFlip} /> : '' },
  ];

  return (
    <div>
      <h1>Governor Forecast</h1>

      <h2>Map</h2>
      <div style={{ marginBottom: '0.75rem' }}>
        <button onClick={() => setMapType('geographic')} style={{ marginRight: '0.5rem', padding: '6px 14px', borderRadius: 6, border: '1px solid #ccc', background: mapType === 'geographic' ? DEM : '#fff', color: mapType === 'geographic' ? '#fff' : '#444', cursor: 'pointer', fontSize: '13px' }}>
          Geographic
        </button>
        <button onClick={() => setMapType('hex')} style={{ padding: '6px 14px', borderRadius: 6, border: '1px solid #ccc', background: mapType === 'hex' ? DEM : '#fff', color: mapType === 'hex' ? '#fff' : '#444', cursor: 'pointer', fontSize: '13px' }}>
          Hex
        </button>
      </div>

      <iframe key={mapType} title="Governor Map" src={mapType === 'geographic' ? GEO_URL : HEX_URL} scrolling="no" frameBorder="0" style={{ width: '100%', height: '800px', border: 'none', borderRadius: 8 }} />

      <h2>All Races</h2>
      <SortableTable
        columns={raceColumns}
        data={raceData}
        defaultSort="_closeness"
        defaultDir="asc"
        pageSize={20}
        colWidths={['10%', '10%', '14%', '14%', '10%', '10%', '10%', '14%', '6%']}
      />
    </div>
  );
}