import { useState, useEffect } from 'react';
import { Bar, Line } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Filler,
  Tooltip,
} from 'chart.js';
import annotationPlugin from 'chartjs-plugin-annotation';

const crosshairPlugin = {
  id: 'crosshair',
  afterDraw(chart) {
    if (chart.tooltip._active && chart.tooltip._active.length) {
      const ctx = chart.ctx;
      const x = chart.tooltip._active[0].element.x;
      const topY = chart.scales.y.top;
      const bottomY = chart.scales.y.bottom;
      ctx.save();
      ctx.beginPath();
      ctx.moveTo(x, topY);
      ctx.lineTo(x, bottomY);
      ctx.lineWidth = 1;
      ctx.strokeStyle = '#aaaaaa';
      ctx.setLineDash([4, 4]);
      ctx.stroke();
      ctx.restore();
    }
  },
};

ChartJS.register(CategoryScale, LinearScale, BarElement, LineElement, PointElement, Filler, Tooltip, annotationPlugin, crosshairPlugin);

const BASE = "https://raw.githubusercontent.com/jkappelmeier/jkappelmeier.github.io/main/Data";
const ELECTION_DAY = new Date('11/3/2026');
const ELECTION_DAY_LABEL = ELECTION_DAY.toLocaleDateString('en-US', { month: 'numeric', day: 'numeric', year: 'numeric' });

const DEM = '#2166ac';
const REP = '#d6232a';
const DEM_LIGHT = 'rgba(33,102,172,0.15)';
const REP_LIGHT = 'rgba(214,35,42,0.15)';

function parseCSVSingle(text) {
  const lines = text.trim().split("\n");
  const headers = lines[0].split(",").map(h => h.trim());
  const vals = lines[1].split(",").map(v => v.trim());
  const obj = {};
  headers.forEach((h, i) => obj[h] = parseFloat(vals[i]));
  return obj;
}

function parseCSVMulti(text) {
  const lines = text.trim().split("\n");
  const headers = lines[0].split(",").map(h => h.trim());
  return lines.slice(1).map(line => {
    const vals = line.split(",").map(v => v.trim());
    const obj = {};
    headers.forEach((h, i) => obj[h] = vals[i]);
    return obj;
  });
}

function pct(v, d=1) { return (parseFloat(v)*100).toFixed(d) + "%"; }

function FlipBadge({ isDem }) {
  return (
    <span style={{
      background: isDem ? '#dbeafe' : '#fee2e2',
      color: isDem ? '#1e40af' : '#991b1b',
      fontSize: '11px',
      fontWeight: 500,
      padding: '2px 7px',
      borderRadius: '99px',
      whiteSpace: 'nowrap',
    }}>+ Flip</span>
  );
}

const GEO_URL = "https://datawrapper.dwcdn.net/SjjRX/3/";
const HEX_URL = "https://datawrapper.dwcdn.net/G4SMT/14/";

function ChartWithElectionLabel({ children }) {
  return (
    <div style={{ position: 'relative', width: '100%', height: '200px', marginBottom: '2rem' }}>
      {children}
      <div style={{ position: 'absolute', bottom: 5, right: -25, fontSize: 11, color: '#555' }}>
        Election day
      </div>
    </div>
  );
}

function SortableTable({ columns, data, defaultSort, defaultDir = 'asc', pageSize = 10, colWidths = [] }) {
  const [sortCol, setSortCol] = useState(defaultSort);
  const [sortDir, setSortDir] = useState(defaultDir);
  const [shown, setShown] = useState(pageSize);

  const handleSort = (col) => {
    if (sortCol === col) {
      setSortDir(d => d === 'asc' ? 'desc' : 'asc');
    } else {
      setSortCol(col);
      setSortDir('asc');
    }
    setShown(pageSize);
  };

  const sorted = [...data].sort((a, b) => {
    const col = columns.find(c => c.key === sortCol);
    const va = col?.sortVal ? col.sortVal(a) : a[sortCol];
    const vb = col?.sortVal ? col.sortVal(b) : b[sortCol];
    if (va < vb) return sortDir === 'asc' ? -1 : 1;
    if (va > vb) return sortDir === 'asc' ? 1 : -1;
    return 0;
  });

  const arrow = (col) => {
    if (sortCol !== col) return ' ↕';
    return sortDir === 'asc' ? ' ↑' : ' ↓';
  };

  return (
    <>
      <table className="race-table">
        {colWidths.length > 0 && (
          <colgroup>
            {colWidths.map((w, i) => <col key={i} style={{ width: w }} />)}
          </colgroup>
        )}
        <thead>
          <tr>
            {columns.map(col => (
              <th key={col.key} onClick={() => handleSort(col.key)} style={{ cursor: 'pointer', userSelect: 'none', whiteSpace: 'nowrap' }}>
                {col.label}{arrow(col.key)}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {sorted.slice(0, shown).map((row, i) => (
            <tr key={i} className={row._rowClass || ''}>
              {columns.map(col => (
                <td key={col.key} className={col.className?.(row) || ''}>
                  {col.render ? col.render(row) : row[col.key]}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
      <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', margin: '0.75rem 0 1.5rem', fontSize: '13px', color: '#666' }}>
        <span>{Math.min(shown, sorted.length)} of {sorted.length}</span>
        {shown < sorted.length && (
          <button onClick={() => setShown(s => s + pageSize)} style={{ padding: '4px 12px', borderRadius: 6, border: '1px solid #ccc', background: '#fff', cursor: 'pointer', fontSize: '13px' }}>
            Show more
          </button>
        )}
        {shown > pageSize && (
          <button onClick={() => setShown(pageSize)} style={{ padding: '4px 12px', borderRadius: 6, border: '1px solid #ccc', background: '#fff', cursor: 'pointer', fontSize: '13px' }}>
            Show less
          </button>
        )}
      </div>
    </>
  );
}

export default function House() {
  const [national, setNational] = useState(null);
  const [races, setRaces] = useState([]);
  const [histogram, setHistogram] = useState([]);
  const [history, setHistory] = useState([]);
  const [polls, setPolls] = useState([]);
  const [loading, setLoading] = useState(true);
  const [mapType, setMapType] = useState('geographic');

  useEffect(() => {
    Promise.all([
      fetch(`${BASE}/HouseNational.csv`).then(r => r.text()),
      fetch(`${BASE}/HouseSnapshot.csv`).then(r => r.text()),
      fetch(`${BASE}/HouseHistogram.csv`).then(r => r.text()),
      fetch(`${BASE}/HouseHistory.csv`).then(r => r.text()),
      fetch(`${BASE}/Polls.csv`).then(r => r.text()),
    ]).then(([natText, raceText, histText, historyText, pollsText]) => {
      setNational(parseCSVSingle(natText));
      setRaces(parseCSVMulti(raceText));
      setHistogram(parseCSVMulti(histText));
      setHistory(parseCSVMulti(historyText));
      setPolls(parseCSVMulti(pollsText).filter(r => r.ElectionType === 'Generic Ballot'));
      setLoading(false);
    });
  }, []);

  if (loading) return <p>Loading...</p>;

  const mean = Math.round(parseFloat(national.DemSeatsMean));

  const sortedHistory = [...history].sort((a, b) => new Date(a.Date) - new Date(b.Date));

  const startDay = new Date(sortedHistory[0]?.Date || '1/1/2026');
  const allDates = [];
  for (let d = new Date(startDay); d <= ELECTION_DAY; d.setDate(d.getDate() + 1)) {
    allDates.push(new Date(d).toLocaleDateString('en-US', { month: 'numeric', day: 'numeric', year: 'numeric' }));
  }

  const historyByDate = {};
  sortedHistory.forEach(r => {
    const d = new Date(r.Date);
    const key = d.toLocaleDateString('en-US', { month: 'numeric', day: 'numeric', year: 'numeric' });
    historyByDate[key] = r;
  });

  const labels = allDates;

  const histMap = (field, transform = v => parseFloat(v)) =>
    allDates.map(d => historyByDate[d] ? transform(historyByDate[d][field]) : null);

  const electionDayAnnotation = {
    type: 'line',
    xMin: ELECTION_DAY_LABEL,
    xMax: ELECTION_DAY_LABEL,
    borderColor: '#555555',
    borderWidth: 1.5,
  };

  const lineDefaults = {
    responsive: true,
    maintainAspectRatio: false,
    interaction: { mode: 'index', intersect: false },
    plugins: {
      legend: { display: false },
      annotation: { annotations: { electionDay: electionDayAnnotation } },
    },
    scales: {
      x: {
        ticks: { maxTicksLimit: 8, autoSkip: true, font: { size: 11 } },
        grid: { display: false },
      },
    },
  };

  const raceData = races.map(r => {
    const demEst = parseFloat(r.DemEstimate);
    const margin = (demEst - 0.5) * 200;
    const closeness = Math.abs(demEst - 0.5);
    const isDemFlip = r.Flip === '1' && parseFloat(r.DemChance) > 0.5;
    return { ...r, _margin: margin, _closeness: closeness, _isDemFlip: isDemFlip, _rowClass: r.Flip === '1' ? 'flip-row' : '' };
  });

  const raceColumns = [
    { key: 'ElectionName', label: 'District', sortVal: r => r.ElectionName },
    { key: 'DemCandidate', label: 'Dem', sortVal: r => r.DemCandidate },
    { key: 'RepCandidate', label: 'Rep', sortVal: r => r.RepCandidate },
    { key: 'DemChance', label: 'Dem chance', sortVal: r => parseFloat(r.DemChance), className: () => 'dem', render: r => pct(r.DemChance) },
    { key: 'RepChance', label: 'Rep chance', sortVal: r => parseFloat(r.RepChance), className: () => 'rep', render: r => pct(r.RepChance) },
    { key: '_margin', label: 'Margin', sortVal: r => r._margin, className: r => r._margin >= 0 ? 'dem' : 'rep', render: r => `${r._margin >= 0 ? 'D+' : 'R+'}${Math.abs(r._margin).toFixed(1)}%` },
    { key: '_closeness', label: 'Competitiveness', sortVal: r => r._closeness, className: () => '', render: r => `${Math.abs(r._margin).toFixed(1)}% margin` },
    { key: 'Flip', label: 'Flip', sortVal: r => r.Flip, render: r => r.Flip === '1' ? <FlipBadge isDem={r._isDemFlip} /> : '' },
  ];

  const pollData = [...polls]
    .sort((a, b) => new Date(b.DateEnd) - new Date(a.DateEnd))
    .map(r => {
      const dem = parseFloat(r.Democrat);
      const rep = parseFloat(r.Republican);
      const margin = dem - rep;
      return { ...r, _margin: margin, _closeness: Math.abs(margin) };
    });

  const pollColumns = [
    { key: 'Poll', label: 'Pollster', sortVal: r => r.Poll },
    { key: 'DateEnd', label: 'Dates', sortVal: r => new Date(r.DateEnd), render: r => `${r.DateStart} – ${r.DateEnd}` },
    { key: 'SampleSize', label: 'Sample', sortVal: r => parseInt(r.SampleSize), render: r => parseInt(r.SampleSize).toLocaleString() },
    { key: 'SampleType', label: 'Type', sortVal: r => r.SampleType },
    { key: 'Democrat', label: 'Dem', sortVal: r => parseFloat(r.Democrat), className: () => 'dem' },
    { key: 'Republican', label: 'Rep', sortVal: r => parseFloat(r.Republican), className: () => 'rep' },
    { key: '_margin', label: 'Dem +/-', sortVal: r => r._margin, className: r => r._margin >= 0 ? 'dem' : 'rep', render: r => `${r._margin >= 0 ? '+' : ''}${r._margin.toFixed(1)}` },
  ];

  return (
    <div>
      <h1>House Forecast</h1>

      <div className="metric-grid">
        <div className="metric">
          <p className="metric-label">Dem seats</p>
          <p className="metric-value dem">{parseFloat(national.DemSeatsMean).toFixed(1)}</p>
          <p className="metric-sub">{national.DemSeatsLow95}–{national.DemSeatsHigh95} (95%)</p>
        </div>
        <div className="metric">
          <p className="metric-label">Rep seats</p>
          <p className="metric-value rep">{parseFloat(national.RepSeatsMean).toFixed(1)}</p>
          <p className="metric-sub">{national.RepSeatsLow95}–{national.RepSeatsHigh95} (95%)</p>
        </div>
        <div className="metric">
          <p className="metric-label">Dem win chance</p>
          <p className="metric-value dem">{pct(national.DemWinChance)}</p>
          <p className="metric-sub">Need 218 seats</p>
        </div>
        <div className="metric">
          <p className="metric-label">Rep win chance</p>
          <p className="metric-value rep">{pct(national.RepWinChance)}</p>
          <p className="metric-sub">Need 218 seats</p>
        </div>
        <div className="metric">
          <p className="metric-label">Dem popular vote</p>
          <p className="metric-value dem">{pct(national.DemPopVoteMean)}</p>
          <p className="metric-sub">{pct(national.DemPopVoteLow95)}–{pct(national.DemPopVoteHigh95)} (95%)</p>
        </div>
        <div className="metric">
          <p className="metric-label">Rep popular vote</p>
          <p className="metric-value rep">{pct(national.RepPopVoteMean)}</p>
          <p className="metric-sub">{pct(national.RepPopVoteLow95)}–{pct(national.RepPopVoteHigh95)} (95%)</p>
        </div>
      </div>

      <h2>Seat distribution</h2>
      <div style={{ position: 'relative', width: '100%', height: '240px', marginBottom: '1.5rem' }}>
        <Bar
          data={{
            labels: histogram.map(r => r.Seats),
            datasets: [{
              data: histogram.map(r => (parseFloat(r.DemSeats) * 100)),
              backgroundColor: histogram.map(r => parseInt(r.Seats) >= 218 ? DEM : REP),
              borderWidth: 0,
              barPercentage: 1.0,
              categoryPercentage: 1.0,
            }],
          }}
          options={{
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
              legend: { display: false },
              tooltip: {
                callbacks: {
                  title: (items) => `${items[0].label} Dem seats`,
                  label: (item) => `Probability: ${item.raw.toFixed(2)}%`,
                },
              },
              annotation: {
                annotations: {
                  meanLine: {
                    type: 'line',
                    xMin: String(mean), xMax: String(mean),
                    borderColor: '#222', borderWidth: 2,
                    label: { display: true, content: `Mean: ${mean}`, position: 'end', yAdjust: -6, font: { size: 11 }, color: '#222', backgroundColor: 'rgba(255,255,255,0.8)' },
                  },
                },
              },
            },
            scales: {
              x: { title: { display: true, text: 'Democratic seats', font: { size: 12 } }, ticks: { maxTicksLimit: 20, autoSkip: true }, grid: { display: false }, min: '180', max: '270' },
              y: { title: { display: true, text: 'Probability (%)', font: { size: 12 } }, grid: { color: '#f0f0f0' } },
            },
          }}
        />
      </div>

      <h2>Map</h2>
      <div style={{ marginBottom: '0.75rem' }}>
        <button onClick={() => setMapType('geographic')} style={{ marginRight: '0.5rem', padding: '6px 14px', borderRadius: 6, border: '1px solid #ccc', background: mapType === 'geographic' ? DEM : '#fff', color: mapType === 'geographic' ? '#fff' : '#444', cursor: 'pointer', fontSize: '13px' }}>Geographic</button>
        <button onClick={() => setMapType('hex')} style={{ padding: '6px 14px', borderRadius: 6, border: '1px solid #ccc', background: mapType === 'hex' ? DEM : '#fff', color: mapType === 'hex' ? '#fff' : '#444', cursor: 'pointer', fontSize: '13px' }}>Hex</button>
      </div>

      <iframe key={mapType} title="House Map" src={mapType === 'geographic' ? GEO_URL : HEX_URL} scrolling="no" frameBorder="0" style={{ width: '100%', height: '800px', border: 'none', borderRadius: 8 }} />

      <h2>Forecast over time</h2>

      <h3 style={{ fontSize: '14px', color: '#555', margin: '0 0 6px' }}>Win chance</h3>
      <ChartWithElectionLabel>
        <Line
          data={{
            labels,
            datasets: [
              { label: 'Dem', data: histMap('DemWinChance', v => parseFloat((parseFloat(v) * 100).toFixed(1))), borderColor: DEM, backgroundColor: 'transparent', borderWidth: 2, pointRadius: 0, tension: 0.3, spanGaps: false },
              { label: 'Rep', data: histMap('RepWinChance', v => parseFloat((parseFloat(v) * 100).toFixed(1))), borderColor: REP, backgroundColor: 'transparent', borderWidth: 2, pointRadius: 0, tension: 0.3, spanGaps: false },
            ],
          }}
          options={{
            ...lineDefaults,
            plugins: {
              ...lineDefaults.plugins,
              tooltip: { mode: 'index', intersect: false, itemSort: (a, b) => b.raw - a.raw, filter: (item) => item.raw !== null, callbacks: { label: (item) => item.raw !== null ? `${item.dataset.label}: ${item.raw.toFixed(1)}%` : null } },
            },
            scales: { ...lineDefaults.scales, y: { min: 0, max: 100, ticks: { callback: (v) => v + '%', font: { size: 11 } }, grid: { color: '#f0f0f0' } } },
          }}
        />
      </ChartWithElectionLabel>

      <h3 style={{ fontSize: '14px', color: '#555', margin: '0 0 6px' }}>Seat estimate</h3>
      <ChartWithElectionLabel>
        <Line
          data={{
            labels,
            datasets: [
              { label: 'Dem high', data: histMap('DemSeatsHigh95'), borderColor: 'transparent', backgroundColor: DEM_LIGHT, pointRadius: 0, fill: '+1', tension: 0.3, spanGaps: false },
              { label: 'Dem seats', data: histMap('DemSeatsMean'), borderColor: DEM, backgroundColor: 'transparent', borderWidth: 2, pointRadius: 0, tension: 0.3, spanGaps: false },
              { label: 'Dem low', data: histMap('DemSeatsLow95'), borderColor: 'transparent', backgroundColor: DEM_LIGHT, pointRadius: 0, fill: '-1', tension: 0.3, spanGaps: false },
              { label: 'Rep seats', data: histMap('RepSeatsMean'), borderColor: REP, backgroundColor: 'transparent', borderWidth: 2, pointRadius: 0, tension: 0.3, spanGaps: false },
              { label: 'Rep high', data: histMap('RepSeatsHigh95'), borderColor: 'transparent', backgroundColor: REP_LIGHT, pointRadius: 0, fill: '+1', tension: 0.3, spanGaps: false },
              { label: 'Rep low', data: histMap('RepSeatsLow95'), borderColor: 'transparent', backgroundColor: REP_LIGHT, pointRadius: 0, fill: '-1', tension: 0.3, spanGaps: false },
            ],
          }}
          options={{
            ...lineDefaults,
            plugins: {
              ...lineDefaults.plugins,
              tooltip: { mode: 'index', intersect: false, itemSort: (a, b) => b.raw - a.raw, filter: (item) => (item.dataset.label === 'Dem seats' || item.dataset.label === 'Rep seats') && item.raw !== null, callbacks: { label: (item) => `${item.dataset.label}: ${parseFloat(item.raw).toFixed(1)}` } },
            },
            scales: { ...lineDefaults.scales, y: { min: 150, max: 285, ticks: { font: { size: 11 } }, grid: { color: '#f0f0f0' } } },
          }}
        />
      </ChartWithElectionLabel>

      <h3 style={{ fontSize: '14px', color: '#555', margin: '0 0 6px' }}>Popular vote estimate</h3>
      <ChartWithElectionLabel>
        <Line
          data={{
            labels,
            datasets: [
              { label: 'Dem high', data: histMap('DemPopVoteHigh95', v => parseFloat(v) * 100), borderColor: 'transparent', backgroundColor: DEM_LIGHT, pointRadius: 0, fill: '+1', tension: 0.3, spanGaps: false },
              { label: 'Dem vote', data: histMap('DemPopVoteMean', v => parseFloat(v) * 100), borderColor: DEM, backgroundColor: 'transparent', borderWidth: 2, pointRadius: 0, tension: 0.3, spanGaps: false },
              { label: 'Dem low', data: histMap('DemPopVoteLow95', v => parseFloat(v) * 100), borderColor: 'transparent', backgroundColor: DEM_LIGHT, pointRadius: 0, fill: '-1', tension: 0.3, spanGaps: false },
              { label: 'Rep vote', data: histMap('RepPopVoteMean', v => parseFloat(v) * 100), borderColor: REP, backgroundColor: 'transparent', borderWidth: 2, pointRadius: 0, tension: 0.3, spanGaps: false },
              { label: 'Rep high', data: histMap('RepPopVoteHigh95', v => parseFloat(v) * 100), borderColor: 'transparent', backgroundColor: REP_LIGHT, pointRadius: 0, fill: '+1', tension: 0.3, spanGaps: false },
              { label: 'Rep low', data: histMap('RepPopVoteLow95', v => parseFloat(v) * 100), borderColor: 'transparent', backgroundColor: REP_LIGHT, pointRadius: 0, fill: '-1', tension: 0.3, spanGaps: false },
            ],
          }}
          options={{
            ...lineDefaults,
            plugins: {
              ...lineDefaults.plugins,
              tooltip: { mode: 'index', intersect: false, itemSort: (a, b) => b.raw - a.raw, filter: (item) => (item.dataset.label === 'Dem vote' || item.dataset.label === 'Rep vote') && item.raw !== null, callbacks: { label: (item) => `${item.dataset.label}: ${parseFloat(item.raw).toFixed(1)}%` } },
            },
            scales: { ...lineDefaults.scales, y: { ticks: { callback: (v) => v.toFixed(1) + '%', font: { size: 11 } }, grid: { color: '#f0f0f0' } } },
          }}
        />
      </ChartWithElectionLabel>

      <h2>All Races</h2>
      <SortableTable
        columns={raceColumns}
        data={raceData}
        defaultSort="_closeness"
        defaultDir="asc"
        pageSize={20}
        colWidths={['12%', '14%', '14%', '10%', '10%', '10%', '14%', '6%']}
      />

      <h2>Generic ballot polls</h2>
      <SortableTable
        columns={pollColumns}
        data={pollData}
        defaultSort="DateEnd"
        defaultDir="desc"
        pageSize={10}
        colWidths={['22%', '22%', '12%', '8%', '8%', '8%', '10%']}
      />
    </div>
  );
}