import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

const BASE = "https://raw.githubusercontent.com/jkappelmeier/jkappelmeier.github.io/main/Data";

function parseCSVSingle(text) {
  const lines = text.trim().split("\n");
  const headers = lines[0].split(",").map(h => h.trim());
  const vals = lines[1].split(",").map(v => v.trim());
  const obj = {};
  headers.forEach((h, i) => obj[h] = parseFloat(vals[i]));
  return obj;
}

function pct(v, d=1) { return (parseFloat(v)*100).toFixed(d) + "%"; }

export default function Home() {
  const [house, setHouse] = useState(null);
  const [senate, setSenate] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      fetch(`${BASE}/HouseNational.csv`).then(r => r.text()),
      fetch(`${BASE}/SenateNational.csv`).then(r => r.text()),
    ]).then(([houseText, senateText]) => {
      setHouse(parseCSVSingle(houseText));
      setSenate(parseCSVSingle(senateText));
      setLoading(false);
    });
  }, []);

  if (loading) return <p>Loading...</p>;

  return (
    <div>
      <h1>2026 Election Forecast</h1>
      <p style={{ color: '#666', marginBottom: '2rem' }}>
        A statistical model combining fundamentals and polling to forecast the 2026 midterm elections.
      </p>

      <div className="home-grid">

        <Link to="/house" className="home-card">
          <h2>House</h2>
          <div className="home-card-row">
            <div>
              <p className="metric-label">Dem seats</p>
              <p className="metric-value dem">{parseFloat(house.DemSeatsMean).toFixed(1)}</p>
              <p className="metric-sub">{house.DemSeatsLow95}–{house.DemSeatsHigh95} (95%)</p>
            </div>
            <div>
              <p className="metric-label">Rep seats</p>
              <p className="metric-value rep">{parseFloat(house.RepSeatsMean).toFixed(1)}</p>
              <p className="metric-sub">{house.RepSeatsLow95}–{house.RepSeatsHigh95} (95%)</p>
            </div>
          </div>
          <div className="home-card-row" style={{ marginTop: '1rem' }}>
            <div>
              <p className="metric-label">Dem win chance</p>
              <p className="metric-value dem">{pct(house.DemWinChance)}</p>
            </div>
            <div>
              <p className="metric-label">Rep win chance</p>
              <p className="metric-value rep">{pct(house.RepWinChance)}</p>
            </div>
          </div>
          <p className="home-card-link">View all races →</p>
        </Link>

        <Link to="/senate" className="home-card">
          <h2>Senate</h2>
          <div className="home-card-row">
            <div>
              <p className="metric-label">Dem seats</p>
              <p className="metric-value dem">{parseFloat(senate.DemSeatsMean).toFixed(1)}</p>
              <p className="metric-sub">{senate.DemSeatsLow95}–{senate.DemSeatsHigh95} (95%)</p>
            </div>
            <div>
              <p className="metric-label">Rep seats</p>
              <p className="metric-value rep">{parseFloat(senate.RepSeatsMean).toFixed(1)}</p>
              <p className="metric-sub">{senate.RepSeatsLow95}–{senate.RepSeatsHigh95} (95%)</p>
            </div>
          </div>
          <div className="home-card-row" style={{ marginTop: '1rem' }}>
            <div>
              <p className="metric-label">Dem win chance</p>
              <p className="metric-value dem">{pct(senate.DemWinChance)}</p>
            </div>
            <div>
              <p className="metric-label">Rep win chance</p>
              <p className="metric-value rep">{pct(senate.RepWinChance)}</p>
            </div>
          </div>
          <p className="home-card-link">View all races →</p>
        </Link>

        <Link to="/gov" className="home-card">
          <h2>Governors</h2>
          <p style={{ color: '#666', fontSize: '14px', margin: '0.5rem 0 1rem' }}>
            38 gubernatorial races across the country.
          </p>
          <p className="home-card-link">View all races →</p>
        </Link>

      </div>
    </div>
  );
}